class Solution2 {
public:
    string smallestStringWithSwaps(string s, vector<vector<int>>& pairs) { 
        unordered_map<int, vector<int>> adj;
        for (const auto& pair : pairs) {
            adj[pair[0]].emplace_back(pair[1]);
            adj[pair[1]].emplace_back(pair[0]);
        }
        unordered_set<int> lookup;
        string result = s;
        for (int i = 0; i < s.length(); ++i) {
            if (lookup.count(i)) {
                continue;
            }
            vector<int> component;
            dfs(i, adj, &lookup, &component);
            sort(component.begin(), component.end());
            vector<char> chars;
            for (const auto& k : component) {
                chars.emplace_back(result[k]);
            }
            sort(chars.begin(), chars.end());
            for (int j = 0; j < component.size(); ++j) {
                result[component[j]] = chars[j];
            }
        }
        return result;
    }

private:
    void dfs(int i, const unordered_map<int, vector<int>>& adj,
             unordered_set<int> *lookup, vector<int> *component) {
        lookup->emplace(i);
        component->emplace_back(i);
        if (!adj.count(i)) {
            return;
        }
        for (const auto& j : adj.at(i)) {
            if (lookup->count(j)) {
                continue;
            }
            dfs(j, adj, lookup, component);
        }
    }
};

# Time:  O(nlogn)
# Space: O(n)

import collections


class UnionFind(object):
    def __init__(self, n):
        self.set = range(n)

    def find_set(self, x):
        if self.set[x] != x:
            self.set[x] = self.find_set(self.set[x])  # path compression.
        return self.set[x]

    def union_set(self, x, y):
        x_root, y_root = map(self.find_set, (x, y))
        if x_root == y_root:
            return False
        self.set[max(x_root, y_root)] = min(x_root, y_root)
        return True


class Solution(object):
    def smallestStringWithSwaps(self, s, pairs):
        """
        :type s: str
        :type pairs: List[List[int]]
        :rtype: str
        """
        union_find = UnionFind(len(s))
        for x,y in pairs: 
            union_find.union_set(x, y)
        components = collections.defaultdict(list)
        for i in xrange(len(s)): 
            components[union_find.find_set(i)].append(s[i])
        for i in components.iterkeys(): 
            components[i].sort(reverse=True)
        result = []
        for i in xrange(len(s)): 
            result.append(components[union_find.find_set(i)].pop())
        return "".join(result)


